// 将模板内容扩充 10 倍长度：把每条内容重复 10 轮，编号递增
function expandContent(text, multiplier = 10) {
    const lines = text.split('\n')
    const expanded = []
    for (let round = 0; round < multiplier; round++) {
        for (const line of lines) {
            // 替换行首编号：如 "1. xxx" → "6. xxx"（按轮次递增）
            const match = line.match(/^(\d+)\.\s(.+)/)
            if (match) {
                const newNum = round * lines.length + parseInt(match[1])
                // 每轮加一个轮次标记，避免完全重复
                const suffix = round > 0 ? `（第${round + 1}轮补充）` : ''
                expanded.push(`${newNum}. ${match[2]}${suffix}`)
            } else {
                expanded.push(line)
            }
        }
    }
    return expanded.join('\n')
}

// 生成 HTML 表格格式的日报内容
function buildReportHtml(today, tomorrow, upcoming) {
    const expToday = expandContent(today)
    const expTomorrow = expandContent(tomorrow)
    const expUpcoming = expandContent(upcoming)
    return `<table border="0" width="100%" cellpadding="0" cellspacing="0"><tbody><tr><td align="left" style="width: 110px;font-weight:600;text-align:center">今日工作内容</td><td align="left">${expToday.replace(/\n/g, '<br>')}</td></tr><tr><td align="left" style="width: 110px;font-weight:600;text-align:center">明日工作计划</td><td align="left">${expTomorrow.replace(/\n/g, '<br>')}</td></tr><tr><td align="left" style="width: 110px;font-weight:600;text-align:center">近期工作安排</td><td align="left">${expUpcoming.replace(/\n/g, '<br>')}</td></tr></tbody></table>`
}

// ============ 工具函数 ============
function rsaEncrypt(text) {
    return crypto.publicEncrypt(
        { key: PUBLIC_KEY, padding: crypto.constants.RSA_PKCS1_PADDING },
        Buffer.from(text, 'utf8')
    ).toString('base64')
}

function post(url, data, cookies = '') {
    return new Promise((resolve, reject) => {
        const parsed = new URL(url)
        const body = JSON.stringify(data)
        const options = {
            hostname: parsed.hostname,
            port: parsed.port || 80,
            path: parsed.pathname,
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'Content-Length': Buffer.byteLength(body),
                ...(cookies ? { Cookie: cookies } : {}),
            },
        }
        const req = http.request(options, res => {
            let raw = ''
            res.on('data', chunk => (raw += chunk))
            res.on('end', () => {
                const setCookies = res.headers['set-cookie'] || []
                try {
                    resolve({ body: JSON.parse(raw), setCookies, status: res.statusCode })
                } catch {
                    resolve({ body: { raw }, setCookies, status: res.statusCode })
                }
            })
        })
        req.on('error', reject)
        req.write(body)
        req.end()
    })
}

async function tryLogin(email, passwords) {
    for (const pwd of passwords) {
        try {
            const encryptedPwd = rsaEncrypt(JSON.stringify({ password: pwd, time: Math.floor(Date.now() / 1000) }))
            const res = await post(USER_API + 'sfhome/login', { email, password: encryptedPwd, sys_lang: 'zh_CN' })
            if (String(res.body.error_code) === '0') {
                return {
                    cookies: res.setCookies.map(c => c.split(';')[0]).join('; '),
                    nickname: res.body.data?.sfuser_info?.nickname || '',
                }
            }
        } catch {
            // 继续下一个密码
        }
    }
    return null
}

async function parallelLimit(tasks, limit) {
    const results = []
    let idx = 0
    const workers = Array(Math.min(limit, tasks.length)).fill(null).map(async () => {
        while (idx < tasks.length) {
            const i = idx++
            results[i] = await tasks[i]()
        }
    })
    await Promise.all(workers)
    return results
}

function getWorkDays(days) {
    const dates = []
    const now = new Date()
    let d = new Date(now)
    while (dates.length < days) {
        d.setDate(d.getDate() - 1)
        const dow = d.getDay()
        if (dow !== 0 && dow !== 6) {
            dates.push(d.toISOString().slice(0, 10))
        }
    }
    return dates
}

// 为一个用户生成日报内容（HTML 表格格式，有重复模拟真实）
function generateReportsForUser(userIdx, dates) {
    const reports = []
    const offset = userIdx % TODAY_TEMPLATES.length
    const favToday = [TODAY_TEMPLATES[offset], TODAY_TEMPLATES[(offset + 1) % TODAY_TEMPLATES.length], TODAY_TEMPLATES[(offset + 2) % TODAY_TEMPLATES.length]]
    const favTomorrow = [TOMORROW_TEMPLATES[offset], TOMORROW_TEMPLATES[(offset + 1) % TOMORROW_TEMPLATES.length], TOMORROW_TEMPLATES[(offset + 2) % TOMORROW_TEMPLATES.length]]
    const favUpcoming = [UPCOMING_TEMPLATES[offset], UPCOMING_TEMPLATES[(offset + 1) % UPCOMING_TEMPLATES.length], UPCOMING_TEMPLATES[(offset + 2) % UPCOMING_TEMPLATES.length]]

    let lastContent = ''
    let repeatCount = 0

    for (const date of dates) {
        // 3天模式不跳过，保证每天都有日报

        const t = Math.floor(Math.random() * favToday.length)
        const content = buildReportHtml(favToday[t], favTomorrow[t], favUpcoming[t])
        lastContent = content
        repeatCount = 0
        reports.push({ date, content })
    }
    return reports
}

// 设置抄送人为阳明
async function setCCToYangming(userCookies, userId) {
    const params = {
        cc_sfuser_id: YANGMING_ID,
        cc_nickname: YANGMING_NICKNAME,
        nickname: YANGMING_NICKNAME,
        sfuser_id: userId,
        type: 'add',
        hash_filter: { obj: '$this', columns: ['nickname'] },
        encrypt_config: {
            res_type: 'sfuser',
            obj: '$this',
            non_encrypt_columns: ['sys_lang', 'version_info', 'cc_sfuser_id', 'nickname', 'sfuser_id', 'type'],
        },
        sys_lang: 'zh_CN',
        sys_site: 'CHN',
    }
    // 模拟前端 handlerParams: intact_columns = 所有 key 除 decrypt_config/hash_filter/page/per_page/sys_lang
    params.intact_columns = Object.keys(params).filter(k =>
        !['decrypt_config', 'hash_filter', 'page', 'per_page', 'sys_lang'].includes(k)
    )
    const res = await post(USER_API + 'daily-report/set-cc-user', params, userCookies)
    return String(res.body.error_code) === '0'
}

// 获取用户的汇报人列表
async function getSuperior(userCookies) {
    const res = await post(USER_API + 'daily-report/get-to-report-users', {
        sys_lang: 'zh_CN',
        sys_site: 'CHN',
        decrypt_config: {
            obj: '$this',
            decrypt_columns: ['report_user', 'cc_user'],
        },
        intact_columns: ['decrypt_config'],
    }, userCookies)
    if (String(res.body.error_code) === '0') {
        return {
            superior: res.body.data?.report_user || [],
            cc: res.body.data?.cc_user || [],
        }
    }
    return { superior: [], cc: [] }
}

// ============ 主流程 ============
async function main() {
    // 1. 读取目标用户 ID 列表
    const idFile = path.join(__dirname, '..', '11')
    const targetIds = new Set(
        fs.readFileSync(idFile, 'utf8').trim().split('\n')
            .map(line => parseInt(line.trim()))
            .filter(id => !isNaN(id))
    )
    console.log(`目标用户: ${targetIds.size} 个`)

    // 2. 用阳明登录
    console.log('\n>>> 阳明登录...')
    const pwd = rsaEncrypt(JSON.stringify({ password: 'qwe123', time: Math.floor(Date.now() / 1000) }))
    const loginRes = await post(USER_API + 'sfhome/login', { email: 'ceshi_yangming@yottastudios.com', password: pwd, sys_lang: 'zh_CN' })
    if (String(loginRes.body.error_code) !== '0') {
        console.error('阳明登录失败:', loginRes.body)
        return
    }
    const adminCookies = loginRes.setCookies.map(c => c.split(';')[0]).join('; ')
    console.log('阳明登录成功')

    // 3. 通过 web-api/staff 获取所有用户 email
    console.log('\n>>> 获取员工列表...')
    const allUsers = []
    let page = 1
    const perPage = 100
    while (true) {
        const res = await post(WEB_API + 'staff', {
            intact_columns: ['department_ids', 'statuses', 'nicknames', 'emails'],
            decrypt_config: { obj: 'sfusers.*', decrypt_columns: ['nickname', 'email'] },
            page,
            per_page: perPage,
            sys_lang: 'zh_CN',
            sys_site: 'CHN',
        }, adminCookies)

        const sfusers = res.body.data?.sfusers || []
        if (sfusers.length === 0) break
        for (const u of sfusers) {
            if (targetIds.has(u.id) && u.email) {
                allUsers.push({ id: u.id, nickname: u.nickname, email: u.email })
            }
        }
        const total = res.body.data?.total || 0
        console.log(`  第 ${page} 页, 已匹配 ${allUsers.length}/${targetIds.size}`)
        if (page * perPage >= total) break
        page++
    }
    console.log(`匹配到 ${allUsers.length} 个目标用户`)

    // 4. 逐用户：登录 → 设置CC → 获取汇报人 → 生成日报
    const workDays = getWorkDays(REPORT_DAYS)
    console.log(`\n>>> 开始生成日报...`)
    console.log(`工作日范围: ${workDays[workDays.length - 1]} ~ ${workDays[0]}（共 ${workDays.length} 天）`)

    let loginSuccess = 0
    let loginFailed = 0
    let ccSuccess = 0
    let totalReports = 0
    let totalFailed = 0
    const loggedInUsers = []

    const userTasks = allUsers.map((user, userIdx) => async () => {
        // 登录
        const loginResult = await tryLogin(user.email, PASSWORDS)
        if (!loginResult) {
            loginFailed++
            if (loginFailed <= 10) console.log(`  [${user.nickname}] 登录失败，跳过`)
            return
        }
        loginSuccess++
        loggedInUsers.push({ id: user.id, nickname: user.nickname, email: user.email })

        // 设置抄送人为阳明
        const ccOk = await setCCToYangming(loginResult.cookies, user.id)
        if (ccOk) ccSuccess++

        // 获取汇报人列表（包含直接主管等）
        const { superior, cc } = await getSuperior(loginResult.cookies)

        // 生成并提交日报
        const reports = generateReportsForUser(userIdx, workDays)
        for (const report of reports) {
            try {
                const res = await post(USER_API + 'daily-report/new-daily-report', {
                    sfuser_id: user.id,
                    content: report.content,
                    cc_user: cc.length ? cc : [YANGMING_NICKNAME],
                    report_date: report.date,
                    is_late: 1,
                    status: 1,
                    hash_filter: { obj: '$this', columns: ['cc_user'] },
                    data: {
                        nickname: user.nickname,
                        cc: cc.length ? cc : [YANGMING_NICKNAME],
                        superior: superior,
                    },
                    encrypt_config: {
                        res_type: 'sfuser',
                        obj: '$this',
                        non_encrypt_columns: ['cc_user', 'files', 'report_date', 'is_late', 'status', 'sys_lang', 'version_info'],
                    },
                    authorize_config: {
                        res_type: 'sfuser',
                        sfusers: [...superior, ...(cc.length ? cc : [YANGMING_NICKNAME])],
                        users: [],
                        emails: [],
                        items: [user.id],
                        operations: ['response', 'send_email'],
                        expire_time: 3600 * 24 * 62,
                    },
                    sys_lang: 'zh_CN',
                    sys_site: 'CHN',
                    intact_columns: ['sfuser_id', 'content', 'cc_user', 'report_date', 'is_late', 'status',
                        'hash_filter', 'data', 'encrypt_config', 'authorize_config'],
                }, loginResult.cookies)

                if (String(res.body.error_code) === '0') {
                    totalReports++
                } else {
                    totalFailed++
                    if (totalFailed <= 5) console.log(`  [${user.nickname}] 日报失败: ${res.body.error_msg}`)
                }
            } catch {
                totalFailed++
            }
        }

        if (loginSuccess % 10 === 0) {
            console.log(`  进度: 登录 ${loginSuccess}, CC ${ccSuccess}, 日报 ${totalReports} 条`)
        }
    })

    await parallelLimit(userTasks, CONCURRENCY)

    fs.writeFileSync(__dirname + '/test-users.json', JSON.stringify(loggedInUsers, null, 2))

    console.log('\n========== 完成 ==========')
    console.log(`匹配用户: ${allUsers.length}`)
    console.log(`登录成功: ${loginSuccess}, 登录失败: ${loginFailed}`)
    console.log(`CC设置成功: ${ccSuccess}`)
    console.log(`日报创建: ${totalReports} 条, 失败: ${totalFailed} 条`)
}

main().catch(e => {
    console.error('执行失败:', e)
    process.exit(1)
})

