    const favTomorrow = [TOMORROW_TEMPLATES[offset], TOMORROW_TEMPLATES[(offset + 1) % TOMORROW_TEMPLATES.length], TOMORROW_TEMPLATES[(offset + 2) % TOMORROW_TEMPLATES.length]]
    const favUpcoming = [UPCOMING_TEMPLATES[offset], UPCOMING_TEMPLATES[(offset + 1) % UPCOMING_TEMPLATES.length], UPCOMING_TEMPLATES[(offset + 2) % UPCOMING_TEMPLATES.length]]

    let lastContent = ''
    let repeatCount = 0

    for (const date of dates) {
        // 3天模式不跳过，保证每天都有日报

        const t = Math.floor(Math.random() * favToday.length)
        const content = buildReportHtml(favToday[t], favTomorrow[t], favUpcoming[t])
        lastContent = content
        repeatCount = 0
        reports.push({ date, content })
    }
    return reports
