// 将模板内容扩充 10 倍长度：把每条内容重复 10 轮，编号递增
function expandContent(text, multiplier = 10) {
    const lines = text.split('\n')
    const expanded = []
    for (let round = 0; round < multiplier; round++) {
        for (const line of lines) {
            // 替换行首编号：如 "1. xxx" → "6. xxx"（按轮次递增）
            const match = line.match(/^(\d+)\.\s(.+)/)
            if (match) {
                const newNum = round * lines.length + parseInt(match[1])
                // 每轮加一个轮次标记，避免完全重复
                const suffix = round > 0 ? `（第${round + 1}轮补充）` : ''
                expanded.push(`${newNum}. ${match[2]}${suffix}`)
            } else {
                expanded.push(line)
            }
        }
    }
    return expanded.join('\n')
}

// 生成 HTML 表格格式的日报内容
function buildReportHtml(today, tomorrow, upcoming) {
    const expToday = expandContent(today)
    const expTomorrow = expandContent(tomorrow)
    const expUpcoming = expandContent(upcoming)
    return `<table border="0" width="100%" cellpadding="0" cellspacing="0"><tbody><tr><td align="left" style="width: 110px;font-weight:600;text-align:center">今日工作内容</td><td align="left">${expToday.replace(/\n/g, '<br>')}</td></tr><tr><td align="left" style="width: 110px;font-weight:600;text-align:center">明日工作计划</td><td align="left">${expTomorrow.replace(/\n/g, '<br>')}</td></tr><tr><td align="left" style="width: 110px;font-weight:600;text-align:center">近期工作安排</td><td align="left">${expUpcoming.replace(/\n/g, '<br>')}</td></tr></tbody></table>`
}

// ============ 工具函数 ============
function rsaEncrypt(text) {
    return crypto.publicEncrypt(
        { key: PUBLIC_KEY, padding: crypto.constants.RSA_PKCS1_PADDING },
        Buffer.from(text, 'utf8')
    ).toString('base64')
}

function post(url, data, cookies = '') {
    return new Promise((resolve, reject) => {
        const parsed = new URL(url)
        const body = JSON.stringify(data)
        const options = {
            hostname: parsed.hostname,
            port: parsed.port || 80,
            path: parsed.pathname,
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'Content-Length': Buffer.byteLength(body),
                ...(cookies ? { Cookie: cookies } : {}),
            },
        }
        const req = http.request(options, res => {
            let raw = ''
            res.on('data', chunk => (raw += chunk))
            res.on('end', () => {
                const setCookies = res.headers['set-cookie'] || []
                try {
                    resolve({ body: JSON.parse(raw), setCookies, status: res.statusCode })
                } catch {
                    resolve({ body: { raw }, setCookies, status: res.statusCode })
                }
            })
        })
        req.on('error', reject)
        req.write(body)
        req.end()
    })
}

async function tryLogin(email, passwords) {
    for (const pwd of passwords) {
        try {
            const encryptedPwd = rsaEncrypt(JSON.stringify({ password: pwd, time: Math.floor(Date.now() / 1000) }))
            const res = await post(USER_API + 'sfhome/login', { email, password: encryptedPwd, sys_lang: 'zh_CN' })
            if (String(res.body.error_code) === '0') {
                return {
                    cookies: res.setCookies.map(c => c.split(';')[0]).join('; '),
                    nickname: res.body.data?.sfuser_info?.nickname || '',
                }
            }
        } catch {
            // 继续下一个密码
        }
    }
    return null
}

async function parallelLimit(tasks, limit) {
    const results = []
    let idx = 0
    const workers = Array(Math.min(limit, tasks.length)).fill(null).map(async () => {
        while (idx < tasks.length) {
            const i = idx++
            results[i] = await tasks[i]()
        }
    })
    await Promise.all(workers)
    return results
}

function getWorkDays(days) {
    const dates = []
    const now = new Date()
    let d = new Date(now)
    while (dates.length < days) {
        d.setDate(d.getDate() - 1)
        const dow = d.getDay()
        if (dow !== 0 && dow !== 6) {
            dates.push(d.toISOString().slice(0, 10))
        }
    }
    return dates
}

// 为一个用户生成日报内容（HTML 表格格式，有重复模拟真实）
function generateReportsForUser(userIdx, dates) {
    const reports = []
    const offset = userIdx % TODAY_TEMPLATES.length
    const favToday = [TODAY_TEMPLATES[offset], TODAY_TEMPLATES[(offset + 1) % TODAY_TEMPLATES.length], TODAY_TEMPLATES[(offset + 2) % TODAY_TEMPLATES.length]]
    const favTomorrow = [TOMORROW_TEMPLATES[offset], TOMORROW_TEMPLATES[(offset + 1) % TOMORROW_TEMPLATES.length], TOMORROW_TEMPLATES[(offset + 2) % TOMORROW_TEMPLATES.length]]
    const favUpcoming = [UPCOMING_TEMPLATES[offset], UPCOMING_TEMPLATES[(offset + 1) % UPCOMING_TEMPLATES.length], UPCOMING_TEMPLATES[(offset + 2) % UPCOMING_TEMPLATES.length]]

    let lastContent = ''
    let repeatCount = 0

    for (const date of dates) {
        // 3天模式不跳过，保证每天都有日报

        const t = Math.floor(Math.random() * favToday.length)
        const content = buildReportHtml(favToday[t], favTomorrow[t], favUpcoming[t])
        lastContent = content
        repeatCount = 0
        reports.push({ date, content })
    }
    return reports
}

