// 将模板内容扩充 10 倍长度：把每条内容重复 10 轮，编号递增
function expandContent(text, multiplier = 10) {
    const lines = text.split('\n')
    const expanded = []
    for (let round = 0; round < multiplier; round++) {
        for (const line of lines) {
            // 替换行首编号：如 "1. xxx" → "6. xxx"（按轮次递增）
            const match = line.match(/^(\d+)\.\s(.+)/)
            if (match) {
                const newNum = round * lines.length + parseInt(match[1])
                // 每轮加一个轮次标记，避免完全重复
                const suffix = round > 0 ? `（第${round + 1}轮补充）` : ''
                expanded.push(`${newNum}. ${match[2]}${suffix}`)
            } else {
                expanded.push(line)
            }
        }
    }
    return expanded.join('\n')
}

