        !['decrypt_config', 'hash_filter', 'page', 'per_page', 'sys_lang'].includes(k)
    )
    const res = await post(USER_API + 'daily-report/set-cc-user', params, userCookies)
    return String(res.body.error_code) === '0'
}

// 获取用户的汇报人列表
async function getSuperior(userCookies) {
    const res = await post(USER_API + 'daily-report/get-to-report-users', {
        sys_lang: 'zh_CN',
        sys_site: 'CHN',
        decrypt_config: {
            obj: '$this',
            decrypt_columns: ['report_user', 'cc_user'],
        },
        intact_columns: ['decrypt_config'],
    }, userCookies)
    if (String(res.body.error_code) === '0') {
        return {
            superior: res.body.data?.report_user || [],
            cc: res.body.data?.cc_user || [],
        }
    }
    return { superior: [], cc: [] }
}

// ============ 主流程 ============
async function main() {
    // 1. 读取目标用户 ID 列表
    const idFile = path.join(__dirname, '..', '11')
    const targetIds = new Set(
        fs.readFileSync(idFile, 'utf8').trim().split('\n')
            .map(line => parseInt(line.trim()))
            .filter(id => !isNaN(id))
    )
    console.log(`目标用户: ${targetIds.size} 个`)

    // 2. 用阳明登录
    console.log('\n>>> 阳明登录...')
    const pwd = rsaEncrypt(JSON.stringify({ password: 'qwe123', time: Math.floor(Date.now() / 1000) }))
    const loginRes = await post(USER_API + 'sfhome/login', { email: 'ceshi_yangming@yottastudios.com', password: pwd, sys_lang: 'zh_CN' })
    if (String(loginRes.body.error_code) !== '0') {
        console.error('阳明登录失败:', loginRes.body)
        return
    }
    const adminCookies = loginRes.setCookies.map(c => c.split(';')[0]).join('; ')
    console.log('阳明登录成功')

    // 3. 通过 web-api/staff 获取所有用户 email
    console.log('\n>>> 获取员工列表...')
    const allUsers = []
    let page = 1
    const perPage = 100
    while (true) {
        const res = await post(WEB_API + 'staff', {
            intact_columns: ['department_ids', 'statuses', 'nicknames', 'emails'],
            decrypt_config: { obj: 'sfusers.*', decrypt_columns: ['nickname', 'email'] },
            page,
            per_page: perPage,
            sys_lang: 'zh_CN',
            sys_site: 'CHN',
        }, adminCookies)

        const sfusers = res.body.data?.sfusers || []
        if (sfusers.length === 0) break
        for (const u of sfusers) {
            if (targetIds.has(u.id) && u.email) {
                allUsers.push({ id: u.id, nickname: u.nickname, email: u.email })
            }
        }
        const total = res.body.data?.total || 0
        console.log(`  第 ${page} 页, 已匹配 ${allUsers.length}/${targetIds.size}`)
        if (page * perPage >= total) break
        page++
    }
    console.log(`匹配到 ${allUsers.length} 个目标用户`)

    // 4. 逐用户：登录 → 设置CC → 获取汇报人 → 生成日报
    const workDays = getWeekAfter0413()
    console.log(`\n>>> 开始生成日报...`)
    console.log(`工作日范围: ${workDays[workDays.length - 1]} ~ ${workDays[0]}（共 ${workDays.length} 天）`)

    let loginSuccess = 0
    let loginFailed = 0
    let ccSuccess = 0
    let totalReports = 0
    let totalFailed = 0
    const loggedInUsers = []

    const userTasks = allUsers.map((user, userIdx) => async () => {
        // 登录
        const loginResult = await tryLogin(user.email, PASSWORDS)
        if (!loginResult) {
            loginFailed++
            if (loginFailed <= 10) console.log(`  [${user.nickname}] 登录失败，跳过`)
            return
        }
        loginSuccess++
        loggedInUsers.push({ id: user.id, nickname: user.nickname, email: user.email })

        // 设置抄送人为阳明
        const ccOk = await setCCToYangming(loginResult.cookies, user.id)
        if (ccOk) ccSuccess++

        // 获取汇报人列表（包含直接主管等）
        const { superior, cc } = await getSuperior(loginResult.cookies)

        // 生成并提交日报
        const reports = generateReportsForUser(userIdx, workDays)
        for (const report of reports) {
            try {
                const res = await post(USER_API + 'daily-report/new-daily-report', {
                    sfuser_id: user.id,
                    content: report.content,
                    cc_user: cc.length ? cc : [YANGMING_NICKNAME],
                    report_date: report.date,
                    is_late: 1,
                    status: 1,
                    hash_filter: { obj: '$this', columns: ['cc_user'] },
                    data: {
                        nickname: user.nickname,
                        cc: cc.length ? cc : [YANGMING_NICKNAME],
                        superior: superior,
                    },
                    encrypt_config: {
                        res_type: 'sfuser',
                        obj: '$this',
                        non_encrypt_columns: ['cc_user', 'files', 'report_date', 'is_late', 'status', 'sys_lang', 'version_info'],
                    },
                    authorize_config: {
                        res_type: 'sfuser',
                        sfusers: [...superior, ...(cc.length ? cc : [YANGMING_NICKNAME])],
                        users: [],
                        emails: [],
                        items: [user.id],
                        operations: ['response', 'send_email'],
                        expire_time: 3600 * 24 * 62,
                    },
                    sys_lang: 'zh_CN',
                    sys_site: 'CHN',
                    intact_columns: ['sfuser_id', 'content', 'cc_user', 'report_date', 'is_late', 'status',
                        'hash_filter', 'data', 'encrypt_config', 'authorize_config'],
                }, loginResult.cookies)

                if (String(res.body.error_code) === '0') {
                    totalReports++
                } else {
                    totalFailed++
                    if (totalFailed <= 5) console.log(`  [${user.nickname}] 日报失败: ${res.body.error_msg}`)
                }
            } catch {
                totalFailed++
            }
        }

        if (loginSuccess % 10 === 0) {
            console.log(`  进度: 登录 ${loginSuccess}, CC ${ccSuccess}, 日报 ${totalReports} 条`)
        }
    })

    await parallelLimit(userTasks, CONCURRENCY)

    fs.writeFileSync(__dirname + '/test-users.json', JSON.stringify(loggedInUsers, null, 2))

    console.log('\n========== 完成 ==========')
    console.log(`匹配用户: ${allUsers.length}`)
    console.log(`登录成功: ${loginSuccess}, 登录失败: ${loginFailed}`)
    console.log(`CC设置成功: ${ccSuccess}`)
    console.log(`日报创建: ${totalReports} 条, 失败: ${totalFailed} 条`)
}

main().catch(e => {
    console.error('执行失败:', e)
    process.exit(1)
})
